def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import heapq

    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError("pygmo is required for hypervolume computations. Install pygmo.") from e

    eps = 1e-12
    tol = 1e-12

    # Normalize input
    if not isinstance(points, np.ndarray):
        pts = np.array(points, dtype=float)
    else:
        pts = points.astype(float)
    if pts.size == 0 or k <= 0:
        if pts.size == 0:
            D = reference_point.shape[0] if reference_point is not None else 0
            if k <= 0:
                return np.zeros((0, 0))
            return np.tile(np.asarray(reference_point, dtype=float).reshape(1, -1), (k, 1)) if D > 0 else np.zeros((k, 0))
        return np.zeros((0, pts.shape[1]))
    if pts.ndim == 1:
        pts = pts.reshape(1, -1)
    N, D = pts.shape

    # reference point
    if reference_point is None:
        reference_point = np.max(pts, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float).reshape(-1)
    if reference_point.shape[0] != D:
        raise ValueError("reference_point must have dimension D = points.shape[1].")

    # Efficient Pareto (nondominated) filtering (minimization assumed)
    def pareto_nondominated(pts_array):
        n = pts_array.shape[0]
        if n == 0:
            return np.array([], dtype=int)
        dominated = np.zeros(n, dtype=bool)
        order = np.argsort(np.sum(pts_array, axis=1))
        for ii in range(n):
            i = order[ii]
            if dominated[i]:
                continue
            # j dominates i if pj <= pi for all and < for some
            le = np.all(pts_array <= pts_array[i], axis=1)
            lt = np.any(pts_array < pts_array[i], axis=1)
            comp = le & lt
            comp[i] = False
            if np.any(comp):
                dominated[i] = True
        return np.where(~dominated)[0]

    nd_idx = pareto_nondominated(pts)
    if nd_idx.size == 0:
        nd_idx = np.arange(N)
    nd_points = pts[nd_idx]
    M = nd_points.shape[0]

    # If few nondominated points, handle directly (pad deterministically)
    if M <= k:
        if M == 0:
            pad = np.tile(reference_point.reshape(1, -1), (k, 1))
            return pad
        subset = nd_points.copy()
        if subset.shape[0] < k:
            last = subset[-1].reshape(1, -1)
            extra = np.repeat(last, k - subset.shape[0], axis=0)
            subset = np.vstack([subset, extra])
        return subset[:k].copy()

    # Stage 1: surrogate + k-NN diversity (modified settings)
    diffs = np.maximum(reference_point - nd_points, eps)
    logprod = np.sum(np.log(diffs), axis=1)  # proxy for single-point HV (larger better)

    # diversity via median distance to sqrt(M) neighbors (exclude self)
    k_neigh = min(10, max(1, int(round(np.sqrt(M)))))  # slightly smaller neighbor cap
    div_scores = np.zeros(M)
    for i in range(M):
        dists = np.linalg.norm(nd_points - nd_points[i], axis=1)
        dists[i] = np.inf
        k_actual = min(k_neigh, M - 1)
        if k_actual > 0:
            nearest = np.partition(dists, k_actual - 1)[:k_actual]
            # use median for robustness
            div_scores[i] = float(np.median(nearest))
        else:
            div_scores[i] = 0.0

    def _norm(x):
        xmin, xmax = x.min(), x.max()
        if xmax - xmin <= eps:
            return np.zeros_like(x)
        return (x - xmin) / (xmax - xmin)

    log_n = _norm(logprod)
    div_n = _norm(div_scores)

    # New additive surrogate with adaptive alpha: small k -> favor HV proxy more; larger k -> favor diversity more
    alpha = 0.6 * (1.0 - min(1.0, k / max(50.0, N))) + 0.2  # in [0.2,0.8], deterministic
    surrogate = alpha * log_n + (1.0 - alpha) * div_n

    # Shortlist moderate and adaptive (different from original aggressive setting)
    shortlist_size = min(M, max(int(3 * k) + 20, 40))
    shortlist_order = np.argsort(-surrogate)[:shortlist_size]
    shortlist_local_idx = shortlist_order
    shortlist_global = nd_idx[shortlist_local_idx]
    shortlist_set = set(int(i) for i in shortlist_global)

    # Ensure shortlist has at least k entries
    if len(shortlist_global) < k:
        need = k - len(shortlist_global)
        remaining = [int(i) for i in nd_idx if int(i) not in shortlist_set]
        add = remaining[:need]
        if add:
            shortlist_global = np.concatenate([shortlist_global, np.array(add, dtype=int)])
            shortlist_set.update(add)

    # Hypervolume cache keyed by tuple(sorted indices)
    hv_cache = {}

    def hv_of_indices(idxs):
        key = tuple(sorted(int(i) for i in idxs))
        if key in hv_cache:
            return hv_cache[key]
        if len(key) == 0:
            hv_cache[key] = 0.0
            return 0.0
        try:
            val = float(pg.hypervolume(pts[list(key)]).compute(reference_point.tolist()))
        except Exception:
            try:
                val = float(pg.hypervolume(pts[list(key)]).compute(reference_point))
            except Exception:
                val = 0.0
        hv_cache[key] = val
        return val

    # CELF lazy greedy: maintain marginal_map {g: (last_size_evaluated, marginal_value)}
    selected_set = set()
    hv_selected = 0.0

    # Precompute singleton hv for shortlist (initial marginals)
    marginal_map = {}
    for g in shortlist_global:
        s = (int(g),)
        marginal_map[int(g)] = (0, hv_of_indices(s))

    # Build max-heap: entries are (-marginal, last_evaluated_size, counter, idx)
    heap = []
    counter = 0
    for g in shortlist_global:
        last_sz, marg = marginal_map[int(g)]
        heapq.heappush(heap, (-marg, last_sz, counter, int(g)))
        counter += 1

    # CELF loop: only recompute when candidate reaches top with stale size
    while len(selected_set) < k and heap:
        neg_marg, last_sz, _cnt, g = heapq.heappop(heap)
        est = -neg_marg
        if g in selected_set:
            continue
        current_size = len(selected_set)
        if last_sz == current_size:
            # accept candidate
            selected_set.add(int(g))
            hv_selected = hv_of_indices(selected_set)
        else:
            # recompute true marginal for current selected_set
            new_set = set(selected_set)
            new_set.add(int(g))
            true_hv = hv_of_indices(new_set)
            true_marg = true_hv - (hv_selected)
            marginal_map[int(g)] = (current_size, true_marg)
            heapq.heappush(heap, (-true_marg, current_size, counter, int(g)))
            counter += 1

    # If not enough selected (heap exhausted), fill with top surrogate from remaining nondominated
    if len(selected_set) < k:
        remaining_global = [int(i) for i in range(N) if int(i) not in selected_set]
        if remaining_global:
            rem_pts = pts[remaining_global]
            rem_diffs = np.maximum(reference_point - rem_pts, eps)
            rem_logprod = np.sum(np.log(rem_diffs), axis=1)
            rem_sur = _norm(rem_logprod)
            order_rem = np.argsort(-rem_sur)
            for idx in order_rem:
                if len(selected_set) >= k:
                    break
                selected_set.add(int(remaining_global[idx]))
                hv_selected = hv_of_indices(selected_set)
        while len(selected_set) < k:
            if len(shortlist_global) > 0:
                selected_set.add(int(shortlist_global[0]))
            else:
                selected_set.add(0)

    # Bounded local first-improvement swap refinement (deterministic order)
    max_swap_iters = min(200, max(10, 10 * k))  # different cap: allow somewhat more iterations for moderate k
    swap_iter = 0
    improved = True
    # Build swap pool: shortlist + few top nondominated by surrogate not already in shortlist
    extra_pool = [int(i) for i in nd_idx if int(i) not in shortlist_set][:min(len(nd_idx), 30)]
    swap_pool = sorted(list(shortlist_set.union(extra_pool)))
    current_hv = hv_of_indices(selected_set)
    while improved and swap_iter < max_swap_iters:
        improved = False
        swap_iter += 1
        for a in sorted(selected_set):
            for b in swap_pool:
                if b in selected_set:
                    continue
                new_set = set(selected_set)
                new_set.remove(int(a))
                new_set.add(int(b))
                new_hv = hv_of_indices(new_set)
                if new_hv > current_hv + tol:
                    selected_set = new_set
                    current_hv = new_hv
                    improved = True
                    break
            if improved:
                break

    final_selected = sorted(list(selected_set))
    # Trim or pad deterministically to size k
    if len(final_selected) > k:
        final_selected = final_selected[:k]
    elif len(final_selected) < k:
        remaining = [i for i in range(N) if int(i) not in final_selected]
        if remaining:
            rem_pts = pts[remaining]
            rem_diffs = np.maximum(reference_point - rem_pts, eps)
            rem_logprod = np.sum(np.log(rem_diffs), axis=1)
            order_rem = np.argsort(-rem_logprod)
            for idx in order_rem:
                if len(final_selected) >= k:
                    break
                final_selected.append(int(remaining[idx]))
        while len(final_selected) < k:
            if len(shortlist_global) > 0:
                final_selected.append(int(shortlist_global[0]))
            else:
                final_selected.append(0)

    subset = pts[np.array(final_selected[:k], dtype=int)]
    return subset.copy()

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import heapq

    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError("pygmo is required for hypervolume computations. Install pygmo.") from e

    rng = np.random.default_rng(42)
    eps = 1e-12
    tol = 1e-12

    # Normalize input
    if not isinstance(points, np.ndarray):
        pts = np.array(points, dtype=float)
    else:
        pts = points.astype(float)
    # Handle trivial cases
    if pts.size == 0 or k <= 0:
        if pts.size == 0:
            if reference_point is None:
                return np.zeros((0, 0))
            D = np.asarray(reference_point).reshape(-1).shape[0]
            if k <= 0:
                return np.zeros((0, 0))
            return np.tile(np.asarray(reference_point, dtype=float).reshape(1, -1), (k, 1)) if D > 0 else np.zeros((k, 0))
        return np.zeros((0, pts.shape[1]))

    if pts.ndim == 1:
        pts = pts.reshape(1, -1)
    N, D = pts.shape

    if reference_point is None:
        reference_point = np.max(pts, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float).reshape(-1)
    if reference_point.shape[0] != D:
        raise ValueError("reference_point must have dimension D = points.shape[1].")

    # Pareto (nondominated) filtering (minimization assumed)
    def pareto_nondominated_idx(X: np.ndarray) -> np.ndarray:
        n = X.shape[0]
        if n == 0:
            return np.array([], dtype=int)
        order = np.argsort(np.sum(X, axis=1))
        dominated = np.zeros(n, dtype=bool)
        for ii in range(n):
            i = order[ii]
            if dominated[i]:
                continue
            le = np.all(X <= X[i], axis=1)
            lt = np.any(X < X[i], axis=1)
            comp = le & lt
            comp[i] = False
            if np.any(comp):
                dominated[i] = True
        return np.where(~dominated)[0]

    nd_idx = pareto_nondominated_idx(pts)
    if nd_idx.size == 0:
        nd_idx = np.arange(N)
    nd_points = pts[nd_idx]
    M = nd_points.shape[0]

    # If few nondominated, handle directly (deterministic padding)
    if M <= k:
        if M == 0:
            pad = np.tile(reference_point.reshape(1, -1), (k, 1))
            return pad
        subset = nd_points.copy()
        if subset.shape[0] < k:
            last = subset[-1].reshape(1, -1)
            extra = np.repeat(last, k - subset.shape[0], axis=0)
            subset = np.vstack([subset, extra])
        return subset[:k].copy()

    # Stage 1: surrogate scoring (log-product) + cheap k-NN diversity (adaptive)
    diffs = np.maximum(reference_point - nd_points, eps)  # (M, D)
    logprod = np.sum(np.log(diffs), axis=1)  # proxy for single-point HV (larger better)

    # Diversity via mean distance to t nearest neighbors (exclude self)
    t = min(10, max(1, int(round(np.sqrt(M)))))
    div_scores = np.zeros(M)
    # compute pairwise distances row-wise to avoid full MxM at once for memory
    for i in range(M):
        dists = np.linalg.norm(nd_points - nd_points[i], axis=1)
        dists[i] = np.inf
        if M - 1 <= t:
            if M > 1:
                div_scores[i] = np.mean(dists[dists != np.inf])
            else:
                div_scores[i] = 0.0
        else:
            ksel = np.partition(dists, t)[:t]
            div_scores[i] = np.mean(ksel)

    def _norm(x):
        xmin = np.min(x)
        xmax = np.max(x)
        if xmax - xmin <= eps:
            return np.zeros_like(x)
        return (x - xmin) / (xmax - xmin)

    log_n = _norm(logprod)
    div_n = _norm(div_scores)

    # combine surrogate with bias towards HV but preserve diversity
    alpha = 0.6  # hv weight
    surrogate = alpha * log_n + (1.0 - alpha) * div_n

    # Adaptive shortlist size: scale with k and D, but bounded
    shortlist_size = int(min(M, max(int(6 * k + 4 * D), 50)))
    shortlist_local_idx = np.argsort(-surrogate, kind="stable")[:shortlist_size]  # indices into nd_points
    shortlist_set_local = set(int(i) for i in shortlist_local_idx)

    # Ensure shortlist >= k
    if len(shortlist_local_idx) < k:
        need = k - len(shortlist_local_idx)
        remaining = [int(i) for i in range(M) if int(i) not in shortlist_set_local]
        add = remaining[:need]
        if add:
            shortlist_local_idx = np.concatenate([shortlist_local_idx, np.array(add, dtype=int)])
            shortlist_set_local.update(add)

    # Hypervolume cache keyed by tuple(sorted local indices)
    hv_cache = {}

    def hv_of_locals(local_idxs):
        key = tuple(sorted(int(i) for i in local_idxs))
        if len(key) == 0:
            return 0.0
        if key in hv_cache:
            return hv_cache[key]
        arr = nd_points[list(key)]
        try:
            val = float(pg.hypervolume(arr).compute(reference_point.tolist()))
        except Exception:
            try:
                val = float(pg.hypervolume(arr).compute(reference_point))
            except Exception:
                val = 0.0
        hv_cache[key] = val
        return val

    # Precompute singleton HVs for shortlist locals (used as initial marginals & tie-break)
    singletons = {}
    for li in shortlist_local_idx:
        singletons[int(li)] = hv_of_locals([int(li)])

    # CELF lazy greedy on local indices (shortlist), index-based with canonical cache
    marginal_cache = {}  # local_idx -> (marginal, last_evaluated_size)
    heap = []
    counter = 0
    for li in shortlist_local_idx:
        marg = float(singletons[int(li)])
        marginal_cache[int(li)] = (marg, 0)
        # tie-break: surrogate, then singleton hv, then local idx
        tie = (float(surrogate[int(li)]), float(marg), int(li))
        heapq.heappush(heap, (-marg, 0, counter, int(li), tie))
        counter += 1

    selected_locals = []
    selected_set_local = set()
    hv_selected = 0.0
    selected_size = 0

    # CELF loop with early stop if top marginal <= 0 (no positive contribution)
    while selected_size < k and heap:
        neg_marg, last_upd, _cnt, li, tie = heapq.heappop(heap)
        est_marg = -neg_marg
        # early stop: if estimated marginal is tiny/nonpositive, break and supplement deterministically
        if est_marg <= tol:
            break
        cached = marginal_cache.get(int(li), (None, -1))
        cached_marg, cached_iter = cached
        if cached_iter == selected_size:
            # accept
            if li in selected_set_local:
                continue
            selected_locals.append(int(li))
            selected_set_local.add(int(li))
            selected_size += 1
            hv_selected = hv_of_locals(selected_locals)
            continue
        else:
            # recompute exact marginal
            if selected_size == 0:
                new_marg = float(singletons[int(li)])
            else:
                hv_with = hv_of_locals(selected_locals + [int(li)])
                new_marg = hv_with - hv_selected
            marginal_cache[int(li)] = (new_marg, selected_size)
            tie2 = (float(surrogate[int(li)]), float(new_marg), int(li))
            heapq.heappush(heap, (-new_marg, selected_size, counter, int(li), tie2))
            counter += 1
            continue

    # If we didn't select k (early stop or heap exhausted), fill deterministically by surrogate from remaining nondominated
    if len(selected_locals) < k:
        need = k - len(selected_locals)
        already = set(selected_locals)
        # rank remaining by surrogate
        remaining_locals = [i for i in range(M) if i not in already]
        if remaining_locals:
            rem_surs = surrogate[remaining_locals]
            order = np.argsort(-rem_surs, kind="stable")
            for idx in order:
                if len(selected_locals) >= k:
                    break
                li = int(remaining_locals[idx])
                if li in selected_set_local:
                    continue
                selected_locals.append(li)
                selected_set_local.add(li)
                hv_selected = hv_of_locals(selected_locals)
        # if still short, pad by repeating best shortlisted
        while len(selected_locals) < k:
            if len(shortlist_local_idx) > 0:
                cand = int(shortlist_local_idx[0])
            else:
                cand = 0
            if cand not in selected_set_local:
                selected_locals.append(cand)
                selected_set_local.add(cand)
            else:
                for i in range(M):
                    if i not in selected_set_local:
                        selected_locals.append(i)
                        selected_set_local.add(i)
                        break
                else:
                    break
            hv_selected = hv_of_locals(selected_locals)

    # Bounded first-improvement swap refinement (use a modest pool)
    max_swap_iters = min(100, 20 * k, 200)
    swap_iter = 0
    improved = True
    # Build swap pool: shortlist locals + top extras by surrogate not in shortlist (bounded)
    extras = [i for i in range(M) if i not in shortlist_set_local][:min(40, M)]
    swap_pool = sorted(set(list(shortlist_set_local) + extras))
    current_hv = hv_of_locals(selected_locals)
    while improved and swap_iter < max_swap_iters:
        improved = False
        swap_iter += 1
        # deterministic order over selected (by their selection order)
        for si_idx in range(len(selected_locals)):
            a = selected_locals[si_idx]
            for b in swap_pool:
                if b in selected_set_local:
                    continue
                swap_iter += 1
                trial = selected_locals.copy()
                trial[si_idx] = int(b)
                hv_trial = hv_of_locals(trial)
                if hv_trial > current_hv + tol:
                    # accept
                    selected_locals = trial
                    selected_set_local = set(selected_locals)
                    current_hv = hv_trial
                    improved = True
                    break
            if improved or swap_iter >= max_swap_iters:
                break

    # Finalize: ensure exactly k elements (deterministic order: as selected_locals)
    final_locals = selected_locals[:k]
    if len(final_locals) < k:
        rem = [i for i in range(M) if i not in final_locals]
        rem_sorted = sorted(rem, key=lambda x: -surrogate[x])
        for r in rem_sorted:
            if len(final_locals) >= k:
                break
            final_locals.append(r)
    final_locals = final_locals[:k]

    subset = nd_points[np.array(final_locals, dtype=int)]
    # ensure shape (k,D)
    if subset.shape[0] < k:
        if subset.size == 0:
            pad_row = reference_point.reshape(1, -1)
        else:
            pad_row = subset[-1].reshape(1, -1)
        pad = np.vstack([pad_row] * (k - subset.shape[0]))
        subset = np.vstack([subset, pad])
    elif subset.shape[0] > k:
        subset = subset[:k]
    return subset.copy()

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import heapq

    try:
        import pygmo as pg
    except Exception:
        raise ImportError("pygmo is required for hypervolume computations. Install pygmo.")

    rng = np.random.default_rng(2026)
    eps = 1e-12
    tol = 1e-12

    # Normalize input
    pts = np.asarray(points, dtype=float)
    if pts.size == 0:
        # nothing to choose from: return k rows of reference_point if available else empty (k,0)
        if k <= 0:
            return np.empty((0, 0))
        if reference_point is None:
            return np.empty((k, 0))
        ref = np.asarray(reference_point, dtype=float).reshape(1, -1)
        return np.repeat(ref, k, axis=0).copy()

    if pts.ndim == 1:
        pts = pts.reshape(1, -1)
    N, D = pts.shape
    if not isinstance(k, int) or k <= 0:
        return np.empty((0, D))

    pad_if_needed = False
    if k > N:
        pad_if_needed = True
        k_eff = N
    else:
        k_eff = k

    # reference point
    if reference_point is None:
        ref = np.max(pts, axis=0) * 1.1
    else:
        ref = np.asarray(reference_point, dtype=float).reshape(-1)
    if ref.shape[0] != D:
        raise ValueError("reference_point must have dimension D = points.shape[1].")

    # Pareto nondominated filtering (minimization assumed)
    def pareto_nondominated_idx(X):
        n = X.shape[0]
        if n == 0:
            return np.array([], dtype=int)
        order = np.argsort(np.sum(X, axis=1))
        dominated = np.zeros(n, dtype=bool)
        for ii in range(n):
            i = order[ii]
            if dominated[i]:
                continue
            le = np.all(X <= X[i], axis=1)
            lt = np.any(X < X[i], axis=1)
            comp = le & lt
            comp[i] = False
            if np.any(comp):
                dominated[i] = True
        return np.where(~dominated)[0]

    nd_idx = pareto_nondominated_idx(pts)
    if nd_idx.size == 0:
        nd_idx = np.arange(N)
    nd_points = pts[nd_idx]
    M = nd_points.shape[0]

    # If few nondominated, return them (pad deterministically)
    if M <= k_eff:
        sel_locals = list(range(M))
        # pad from remaining by surrogate if needed to reach k_eff
        if len(sel_locals) < k_eff:
            remaining = [i for i in range(N) if i not in nd_idx[sel_locals]]
            if remaining:
                rem_pts = pts[remaining]
                scores = np.sum(np.log(np.maximum(ref - rem_pts, eps)), axis=1)
                order = np.argsort(-scores, kind='stable')
                for idx in order:
                    if len(sel_locals) >= k_eff:
                        break
                    sel_locals.append(int(remaining[int(idx)]))  # note: this mixes indices; handle below
            while len(sel_locals) < k_eff:
                sel_locals.append(sel_locals[-1] if sel_locals else 0)
        # convert possible global indices back to points: make rows
        chosen = []
        for v in sel_locals[:k_eff]:
            if v < M:
                chosen.append(nd_points[int(v)])
            else:
                # v was a global index from remaining; use pts[v]
                chosen.append(pts[int(v)])
        res = np.vstack(chosen)
        if pad_if_needed:
            while res.shape[0] < k:
                res = np.vstack([res, res[-1:]])
        return res.reshape((k, D))

    # Stage 1: surrogate scoring: stable log-product + cheap diversity via KDTree (fallback to partitioned distances)
    diffs = np.maximum(ref - nd_points, eps)
    logprod = np.sum(np.log(diffs), axis=1)  # higher better

    # diversity via nearest neighbors (use cKDTree if available)
    try:
        from scipy.spatial import cKDTree as KDTree
        k_neigh = min(8, max(1, int(round(np.sqrt(M)))))
        tree = KDTree(nd_points)
        # query k_neigh+1 because includes self
        kq = min(M, k_neigh + 1)
        dists, idxs = tree.query(nd_points, k=kq, n_jobs=1)
        # dists shape (M, kq)
        if kq == 1:
            # only self in very small sets
            div_scores = np.zeros(M)
        else:
            # exclude self (first column zero)
            if dists.ndim == 1:
                div_scores = np.zeros(M)
            else:
                # take mean of nearest neighbors excluding self
                if kq > 1:
                    div_scores = np.mean(dists[:, 1:], axis=1)
                else:
                    div_scores = np.zeros(M)
    except Exception:
        # fallback: partitioned distances loop but capped neighbors small
        k_neigh = min(8, max(1, int(round(np.sqrt(M)))))
        div_scores = np.zeros(M)
        for i in range(M):
            d = np.linalg.norm(nd_points - nd_points[i], axis=1)
            d[i] = np.inf
            k_actual = min(k_neigh, M - 1)
            if k_actual > 0:
                div_scores[i] = np.mean(np.partition(d, k_actual - 1)[:k_actual])
            else:
                div_scores[i] = 0.0

    def _norm(x):
        xmin = np.min(x)
        xmax = np.max(x)
        if xmax - xmin <= eps:
            return np.zeros_like(x)
        return (x - xmin) / (xmax - xmin)

    log_n = _norm(logprod)
    div_n = _norm(div_scores)
    alpha = 0.65
    surrogate = alpha * log_n + (1.0 - alpha) * div_n

    # Tight, cost-aware shortlist
    shortlist_size = int(min(M, max(6 * k_eff, 40)))
    shortlist_local_idx = np.argsort(-surrogate, kind='stable')[:shortlist_size]
    shortlist_local_idx = np.unique(shortlist_local_idx)  # ensure unique
    S = shortlist_local_idx.size

    # Work with local indices into nd_points for all exact HV calls to reduce copies
    hv_cache = {}

    def hv_of_local_indices(local_idxs):
        # local_idxs: iterable of ints (indices into nd_points)
        key = tuple(sorted(int(i) for i in local_idxs))
        if len(key) == 0:
            return 0.0
        if key in hv_cache:
            return hv_cache[key]
        arr = nd_points[list(key)]
        try:
            val = float(pg.hypervolume(arr).compute(ref.tolist()))
        except Exception:
            val = float(pg.hypervolume(arr).compute(ref))
        hv_cache[key] = val
        return val

    # Precompute singleton HVs for shortlist locals
    singleton = {}
    for li in shortlist_local_idx:
        singleton[int(li)] = hv_of_local_indices([int(li)])

    # CELF lazy greedy on local shortlist indices
    marginal_cache = {}  # li -> (marg, last_updated_size)
    heap = []
    counter = 0
    for li in shortlist_local_idx:
        marg = float(singleton.get(int(li), 0.0))
        marginal_cache[int(li)] = (marg, 0)
        tie = float(surrogate[int(li)]) + 1e-15 * marg  # deterministic tie-break
        heapq.heappush(heap, (-marg, 0, counter, int(li), tie))
        counter += 1

    selected_locals = []
    selected_set_local = set()
    hv_selected = 0.0
    selected_size = 0

    # CELF main loop with early stopping when best marginal <= 0
    while selected_size < k_eff and heap:
        neg_marg, last_upd, _cnt, li, tie = heapq.heappop(heap)
        if int(li) in selected_set_local:
            continue
        est = -neg_marg
        if last_upd == selected_size:
            # cached valid
            if est <= tol:
                break
            selected_locals.append(int(li))
            selected_set_local.add(int(li))
            selected_size += 1
            hv_selected = hv_of_local_indices(selected_locals)
            continue
        # recompute true marginal
        if selected_size == 0:
            true_marg = float(singleton[int(li)])
        else:
            hv_with = hv_of_local_indices(selected_locals + [int(li)])
            true_marg = hv_with - hv_selected
        marginal_cache[int(li)] = (true_marg, selected_size)
        tie2 = float(surrogate[int(li)]) + 1e-15 * true_marg
        heapq.heappush(heap, (-true_marg, selected_size, counter, int(li), tie2))
        counter += 1

    # Fill remaining slots deterministically by surrogate (from shortlist then all nd_points)
    if len(selected_locals) < k_eff:
        already = set(selected_locals)
        # first from shortlisted by surrogate
        for li in shortlist_local_idx:
            if len(selected_locals) >= k_eff:
                break
            if int(li) in already:
                continue
            selected_locals.append(int(li))
            selected_set_local.add(int(li))
            hv_selected = hv_of_local_indices(selected_locals)
            already.add(int(li))
        # then from all nondominated by surrogate
        if len(selected_locals) < k_eff:
            rem_all = [i for i in range(M) if i not in already]
            rem_sorted = sorted(rem_all, key=lambda x: -surrogate[int(x)])
            for ri in rem_sorted:
                if len(selected_locals) >= k_eff:
                    break
                selected_locals.append(int(ri))
                selected_set_local.add(int(ri))
                hv_selected = hv_of_local_indices(selected_locals)
                already.add(int(ri))

    # Ensure exactly k_eff elements
    if len(selected_locals) < k_eff:
        last_choice = int(shortlist_local_idx[0]) if shortlist_local_idx.size > 0 else 0
        while len(selected_locals) < k_eff:
            if last_choice not in selected_set_local:
                selected_locals.append(last_choice)
                selected_set_local.add(last_choice)
            else:
                for i in range(M):
                    if i not in selected_set_local:
                        selected_locals.append(i)
                        selected_set_local.add(i)
                        break
                else:
                    break
        hv_selected = hv_of_local_indices(selected_locals)

    selected_locals = selected_locals[:k_eff]
    selected_set_local = set(selected_locals)
    current_hv = hv_of_local_indices(selected_locals)

    # Swap refinement: small bounded first-improvement pool
    swap_budget = min(80, max(10 * k_eff, 40))
    swaps = 0
    improved = True
    # swap pool: shortlist locals + a few extras from top nondominated not in shortlist
    extras = [i for i in range(M) if i not in shortlist_local_idx][:min(30, M)]
    swap_pool = list(dict.fromkeys(list(shortlist_local_idx) + extras))
    swap_pool = [int(x) for x in swap_pool]

    while improved and swaps < swap_budget:
        improved = False
        for pos in range(len(selected_locals)):
            if swaps >= swap_budget:
                break
            a = int(selected_locals[pos])
            for b in swap_pool:
                if swaps >= swap_budget:
                    break
                if int(b) in selected_set_local:
                    continue
                swaps += 1
                trial = list(selected_locals)
                trial[pos] = int(b)
                trial_set = set(trial)
                trial_hv = hv_of_local_indices(trial)
                if trial_hv > current_hv + 1e-12:
                    selected_locals = trial
                    selected_set_local = trial_set
                    current_hv = trial_hv
                    improved = True
                    break
            if improved:
                break

    final_locals = selected_locals[:k_eff]
    # Map locals to original indices and build result
    final_globals = [int(nd_idx[int(li)]) for li in final_locals]
    result = pts[np.array(final_globals, dtype=int)].copy()

    # pad if original k larger than N
    if pad_if_needed:
        while result.shape[0] < k:
            result = np.vstack([result, result[-1:]])
    elif result.shape[0] > k:
        result = result[:k]

    # ensure exact shape (k, D)
    if result.shape[0] < k:
        pad_row = result[-1].reshape(1, -1) if result.size else ref.reshape(1, -1)
        extra = np.vstack([pad_row] * (k - result.shape[0]))
        result = np.vstack([result, extra])

    return result.reshape((k, D))

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import heapq

    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError("pygmo is required for hypervolume computations. Install pygmo.") from e

    # Optional KDTree for faster neighbor queries
    try:
        from sklearn.neighbors import KDTree  # type: ignore
        _has_kdtree = True
    except Exception:
        _has_kdtree = False

    rng = np.random.default_rng(123456)
    eps = 1e-12
    tol = 1e-12

    # Normalize input
    if not isinstance(points, np.ndarray):
        pts = np.array(points, dtype=float)
    else:
        pts = points.astype(float)
    if pts.size == 0 or k <= 0:
        if pts.size == 0:
            D = reference_point.shape[0] if reference_point is not None else 0
            if k <= 0:
                return np.zeros((0, 0))
            if D > 0:
                return np.tile(np.asarray(reference_point, dtype=float).reshape(1, -1), (k, 1))
            return np.zeros((k, 0))
        return np.zeros((0, pts.shape[1]))
    if pts.ndim == 1:
        pts = pts.reshape(1, -1)
    N, D = pts.shape

    # reference point
    if reference_point is None:
        reference_point = np.max(pts, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float).reshape(-1)
    if reference_point.shape[0] != D:
        raise ValueError("reference_point must have dimension D = points.shape[1].")

    # Pareto nondominated (minimization)
    def pareto_nondominated(pts_array):
        n = pts_array.shape[0]
        if n == 0:
            return np.array([], dtype=int)
        order = np.argsort(np.sum(pts_array, axis=1))
        dominated = np.zeros(n, dtype=bool)
        for ii in range(n):
            i = order[ii]
            if dominated[i]:
                continue
            le = np.all(pts_array <= pts_array[i], axis=1)
            lt = np.any(pts_array < pts_array[i], axis=1)
            comp = le & lt
            comp[i] = False
            if np.any(comp):
                dominated[i] = True
        return np.where(~dominated)[0]

    nd_idx = pareto_nondominated(pts)
    if nd_idx.size == 0:
        nd_idx = np.arange(N)
    nd_points = pts[nd_idx]
    M = nd_points.shape[0]

    # If few nondominated points, return/pad deterministically
    if M <= k:
        if M == 0:
            pad = np.tile(reference_point.reshape(1, -1), (k, 1))
            return pad
        subset = nd_points.copy()
        if subset.shape[0] < k:
            last = subset[-1].reshape(1, -1)
            extra = np.repeat(last, k - subset.shape[0], axis=0)
            subset = np.vstack([subset, extra])
        return subset[:k].copy()

    # Quick HV-proxy: log-product of distances to reference (higher is better)
    diffs = np.maximum(reference_point - nd_points, eps)
    logprod = np.sum(np.log(diffs), axis=1)

    # Diversity proxy using KDTree if available, else vectorized partition on nd_points
    k_neigh = min(12, max(1, int(round(np.sqrt(M)))))
    div_scores = np.zeros(M)
    if _has_kdtree and M > 1:
        try:
            tree = KDTree(nd_points)
            # query k_neigh+1 because includes self
            kq = min(M, k_neigh + 1)
            dists, idxs = tree.query(nd_points, k=kq)
            # first column is zero (self)
            for i in range(M):
                act = dists[i, 1:kq]
                if act.size > 0:
                    div_scores[i] = float(np.mean(act))
                else:
                    div_scores[i] = 0.0
        except Exception:
            # fallback
            for i in range(M):
                d = np.linalg.norm(nd_points - nd_points[i], axis=1)
                d[i] = np.inf
                kact = min(k_neigh, M - 1)
                if kact > 0:
                    div_scores[i] = np.mean(np.partition(d, kact - 1)[:kact])
                else:
                    div_scores[i] = 0.0
    else:
        for i in range(M):
            d = np.linalg.norm(nd_points - nd_points[i], axis=1)
            d[i] = np.inf
            kact = min(k_neigh, M - 1)
            if kact > 0:
                div_scores[i] = np.mean(np.partition(d, kact - 1)[:kact])
            else:
                div_scores[i] = 0.0

    def _norm(x):
        xmin, xmax = x.min(), x.max()
        if xmax - xmin <= eps:
            return np.zeros_like(x)
        return (x - xmin) / (xmax - xmin)

    lp_n = _norm(logprod)
    dv_n = _norm(div_scores)

    # New score mixing: stronger emphasis on diversity for shortlist, different smoothing
    # surrogate = alpha * lp_n * (beta + (1-beta) * dv_n) + (1-alpha) * (gamma + (1-gamma) * dv_n)
    alpha = 0.55
    beta = 0.35
    gamma = 0.6
    surrogate = alpha * lp_n * (beta + (1.0 - beta) * dv_n) + (1.0 - alpha) * (gamma + (1.0 - gamma) * dv_n)

    # Tighten shortlist adaptively (more conservative than original)
    shortlist_size = min(M, max(int(3 * k + 10 * (D ** 0.25)), 30))
    shortlist_local_idx = np.argsort(-surrogate)[:shortlist_size]
    shortlist_global = nd_idx[shortlist_local_idx]
    shortlist_set = set(int(i) for i in shortlist_global)

