            le = np.all(X[order] <= X[i], axis=1)
            lt = np.any(X[order] < X[i], axis=1)
            comp = le & lt
            # map back to original indices
            dominated_indices = order[comp]
            # mark dominated points (they are dominated by some earlier point)
            is_dom[dominated_indices] = True
        return np.where(~is_dom)[0]

    nd_idx = pareto_nondominated_idx(pts)
    if nd_idx.size == 0:
        nd_idx = np.arange(N)
    nd_points = pts[nd_idx]
    M = nd_points.shape[0]

    # If few nondominated points, deterministic return/pad
    if M <= k:
        if M == 0:
            pad = np.tile(reference_point.reshape(1, -1), (k, 1))
            return pad
        subset = nd_points.copy()
        if subset.shape[0] < k:
            # pad by repeating worst (last) nondominated deterministically
            last = subset[-1].reshape(1, -1)
            extra = np.repeat(last, k - subset.shape[0], axis=0)
            subset = np.vstack([subset, extra])
        return subset[:k].copy()

    # HV-proxy: log-product of distances to reference (higher better)
    diffs = np.maximum(reference_point - nd_points, eps)
    logprod = np.sum(np.log(diffs), axis=1)

    # Diversity proxy: mean distance to nearest neighbors via KDTree if available
    k_neigh = min(12, max(1, int(round(np.sqrt(M)))))
    try:
        from scipy.spatial import cKDTree
        tree = cKDTree(nd_points)
        # query k_neigh+1 because includes self at distance 0
        kk = min(M, k_neigh + 1)
        dists, idxs = tree.query(nd_points, k=kk, n_jobs=1)
        # handle when kk==1 single column
        if dists.ndim == 1:
            # only self returned
            mean_nn = np.zeros(M, dtype=float)
        else:
            # exclude self (first col)
            dists_no_self = dists[:, 1:kk]
            # if fewer neighbors than k_neigh exist, take mean across available
            mean_nn = np.mean(dists_no_self, axis=1)
    except Exception:
        # fallback to pairwise in chunks to avoid full M^2 allocation for large M
        mean_nn = np.zeros(M, dtype=float)
        if M <= 2000:
            diff_mat = nd_points[:, None, :] - nd_points[None, :, :]
            dmat = np.linalg.norm(diff_mat, axis=2)
            for i in range(M):
                row = dmat[i].copy()
                row[i] = np.inf
                k_act = min(k_neigh, M - 1)
                if k_act > 0:
                    mean_nn[i] = np.mean(np.partition(row, k_act - 1)[:k_act])
                else:
                    mean_nn[i] = 0.0
        else:
            # chunked approach
            for i in range(M):
                dists_i = np.linalg.norm(nd_points - nd_points[i], axis=1)
                dists_i[i] = np.inf
                k_act = min(k_neigh, M - 1)
                if k_act > 0:
                    mean_nn[i] = np.mean(np.partition(dists_i, k_act - 1)[:k_act])
                else:
                    mean_nn[i] = 0.0

    def _norm(x):
        xmin, xmax = x.min(), x.max()
        if xmax - xmin <= eps:
            return np.zeros_like(x)
        return (x - xmin) / (xmax - xmin)

    lp_n = _norm(logprod)
    dv_n = _norm(mean_nn)

    # Tight surrogate that favors diversity but keeps HV-proxy signal
    surrogate = 0.35 * lp_n + 0.55 * dv_n + 0.10 * (lp_n * dv_n)

    # Build compact shortlist: O(k) with modest floor, deterministic selection
    shortlist_size = min(M, max(int(4 * k + 8), 30))  # modest constant factor
    shortlist_local_idx = np.argsort(-surrogate)[:shortlist_size]
    shortlist_global = nd_idx[shortlist_local_idx].astype(int)
    shortlist_set = set(int(i) for i in shortlist_global)

    # Ensure at least k candidates in shortlist (deterministic)
    if len(shortlist_global) < k:
        needed = k - len(shortlist_global)
        remaining = [int(i) for i in nd_idx if int(i) not in shortlist_set]
        add = remaining[:needed]
        if add:
            shortlist_global = np.concatenate([shortlist_global, np.array(add, dtype=int)])
            shortlist_set.update(add)

    # Canonical HV cache keyed by sorted tuple of ints
    hv_cache = {}

    def hv_of_indices(idxs):
        # idxs: iterable of ints or set; canonicalize to sorted tuple
        if isinstance(idxs, int):
            key = (int(idxs),)
        else:
            try:
                key = tuple(sorted(int(i) for i in idxs))
            except Exception:
                key = tuple(sorted(int(idxs),))
        if key in hv_cache:
            return hv_cache[key]
        if len(key) == 0:
            hv_cache[key] = 0.0
            return 0.0
        try:
            val = float(pg.hypervolume(pts[list(key)]).compute(reference_point.tolist()))
        except Exception:
            try:
                val = float(pg.hypervolume(pts[list(key)]).compute(reference_point))
            except Exception:
                val = 0.0
        hv_cache[key] = val
        return val

    # Precompute singleton HVs for shortlist (seed CELF)
    singleton_hv = {}
    for g in shortlist_global:
        gi = int(g)
        singleton_hv[gi] = hv_of_indices((gi,))

    # CELF lazy greedy
    selected_set = set()
    hv_selected = 0.0

    marginal_map = {}  # idx -> (last_size, marginal_estimate)
    heap = []
    counter = 0
    for g in shortlist_global:
        gi = int(g)
        last_sz = 0
        marg = singleton_hv.get(gi, hv_of_indices((gi,)))
        marginal_map[gi] = (last_sz, marg)
        heapq.heappush(heap, (-marg, last_sz, counter, gi))
        counter += 1

    # Greedy loop: pick up to k elements, lazy updates, early stop when best marginal <= tol
    while len(selected_set) < k and heap:
        neg_marg, last_sz, _cnt, g = heapq.heappop(heap)
        if int(g) in selected_set:
            continue
        est = -neg_marg
        cur_size = len(selected_set)
        if last_sz == cur_size:
            if est <= tol:
                break
            selected_set.add(int(g))
            hv_selected = hv_of_indices(selected_set)
            continue
        # recompute true marginal
        new_set = set(selected_set)
        new_set.add(int(g))
        true_hv = hv_of_indices(new_set)
        true_marg = true_hv - hv_selected
        marginal_map[int(g)] = (cur_size, true_marg)
        heapq.heappush(heap, (-true_marg, cur_size, counter, int(g)))
        counter += 1

    # If not enough selected, fill deterministically by surrogate among remaining nondominated
    if len(selected_set) < k:
        remaining_global = [int(i) for i in nd_idx if int(i) not in selected_set]
        if remaining_global:
            rem_pts = pts[remaining_global]
            rem_diffs = np.maximum(reference_point - rem_pts, eps)
            rem_logprod = np.sum(np.log(rem_diffs), axis=1)
            rem_sur = _norm(rem_logprod)
            order_rem = np.argsort(-rem_sur)
            for idx in order_rem:
                if len(selected_set) >= k:
                    break
                selected_set.add(int(remaining_global[idx]))
                hv_selected = hv_of_indices(selected_set)
        while len(selected_set) < k:
            # fallback deterministic pad
            if len(shortlist_global) > 0:
                selected_set.add(int(shortlist_global[0]))
            else:
                selected_set.add(0)

    # Bounded first-improvement swap refinement
    max_swap_iters = min(50, 10 * k)
    swap_iter = 0
    improved = True
    # Build swap_pool: shortlist plus a small number of extras from nondominated not in shortlist
    extra_candidates = [int(i) for i in nd_idx if int(i) not in shortlist_set]
    extra_limit = min(len(extra_candidates), max(10, k))
    swap_pool = sorted(list(shortlist_set.union(extra_candidates[:extra_limit])))
    current_hv = hv_of_indices(selected_set)

    while improved and swap_iter < max_swap_iters:
        improved = False
        swap_iter += 1
        # deterministic iterate over selected in sorted order for reproducibility
        for a in sorted(selected_set):
            for b in swap_pool:
                if int(b) in selected_set:
                    continue
                # first-improvement: try swap a->b
                new_set = set(selected_set)
                new_set.remove(int(a))
                new_set.add(int(b))
                new_hv = hv_of_indices(new_set)
                if new_hv > current_hv + tol:
                    selected_set = new_set
                    current_hv = new_hv
                    hv_selected = new_hv
                    improved = True
                    break
            if improved:
                break

    final_selected = sorted(list(selected_set))

    # Trim or pad deterministically to size k
    if len(final_selected) > k:
        final_selected = final_selected[:k]
    elif len(final_selected) < k:
        remaining = [i for i in range(N) if int(i) not in final_selected]
        if remaining:
            rem_pts = pts[remaining]
            rem_diffs = np.maximum(reference_point - rem_pts, eps)
            rem_logprod = np.sum(np.log(rem_diffs), axis=1)
            order_rem = np.argsort(-rem_logprod)
            for idx in order_rem:
                if len(final_selected) >= k:
                    break
                final_selected.append(int(remaining[idx]))
        while len(final_selected) < k:
            if len(shortlist_global) > 0:
                final_selected.append(int(shortlist_global[0]))
            else:
                final_selected.append(0)

    subset = pts[np.array(final_selected[:k], dtype=int)]
    return subset.copy()

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import heapq

    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError("pygmo is required for hypervolume computations. Install pygmo.") from e

    # deterministic
    rng = np.random.default_rng(42)
    eps = 1e-12
    tol = 1e-12

    # Normalize input
    if not isinstance(points, np.ndarray):
        pts = np.array(points, dtype=float)
    else:
        pts = points.astype(float)
    # handle trivial cases
    if pts.size == 0 or k <= 0:
        if pts.size == 0:
            if reference_point is None:
                return np.zeros((0, 0))
            D = np.asarray(reference_point).reshape(-1).shape[0]
            if k <= 0:
                return np.zeros((0, 0))
            return np.tile(np.asarray(reference_point, dtype=float).reshape(1, -1), (k, 1)) if D > 0 else np.zeros((k, 0))
        return np.zeros((0, pts.shape[1]))

    if pts.ndim == 1:
        pts = pts.reshape(1, -1)
    N, D = pts.shape

    # reference point
    if reference_point is None:
        reference_point = np.max(pts, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float).reshape(-1)
    if reference_point.shape[0] != D:
        raise ValueError("reference_point must have dimension D = points.shape[1].")

    # Pareto nondominated filtering (minimization assumed)
    def pareto_nondominated_idx(X: np.ndarray) -> np.ndarray:
        n = X.shape[0]
        if n == 0:
            return np.array([], dtype=int)
        order = np.argsort(np.sum(X, axis=1))  # deterministic
        dominated = np.zeros(n, dtype=bool)
        for ii in range(n):
            i = order[ii]
            if dominated[i]:
                continue
            le = np.all(X <= X[i], axis=1)
            lt = np.any(X < X[i], axis=1)
            comp = le & lt
            comp[i] = False
            if np.any(comp):
                dominated[i] = True
        return np.where(~dominated)[0]

    nd_idx = pareto_nondominated_idx(pts)
    if nd_idx.size == 0:
        nd_idx = np.arange(N)
    nd_points = pts[nd_idx]
    M = nd_points.shape[0]

    # If few nondominated, return/pad deterministically
    if M <= k:
        if M == 0:
            pad = np.tile(reference_point.reshape(1, -1), (k, 1))
            return pad
        subset = nd_points.copy()
        if subset.shape[0] < k:
            last = subset[-1].reshape(1, -1)
            extra = np.repeat(last, k - subset.shape[0], axis=0)
            subset = np.vstack([subset, extra])
        return subset[:k].copy()

    # Stage 1: surrogate scoring (weaker HV proxy + stronger diversity)
    diffs = np.maximum(reference_point - nd_points, eps)  # (M, D)
    # use log-produc proxy but slightly damped to favor diversity
    logprod = np.sum(np.log(diffs), axis=1)  # larger better
    # normalize helper
    def _norm(x):
        xmin = np.min(x)
        xmax = np.max(x)
        if xmax - xmin <= eps:
            return np.zeros_like(x)
        return (x - xmin) / (xmax - xmin)

    log_n = _norm(logprod)

    # Diversity via kNN mean distance using KDTree if available
    t = max(1, int(max(1, round(np.sqrt(M) / 2.0))))  # fewer neighbors than original
    try:
        from scipy.spatial import cKDTree as KDTree
    except Exception:
        try:
            from scipy.spatial import KDTree
        except Exception:
            KDTree = None

    div_scores = np.empty(M, dtype=float)
    if KDTree is not None:
        tree = KDTree(nd_points)
        # query k=t+1 because includes self
        # deterministic: if M small, adjust
        qk = min(M, t + 1)
        dists, idxs = tree.query(nd_points, k=qk, p=2, n_jobs=1)
        # ensure shapes
        if qk == 1:
            dists = dists.reshape(M, 1)
        for i in range(M):
            ds = dists[i]
            if ds.ndim == 0:
                ds = np.array([ds])
            # remove self (distance zero) if present
            if ds.size > 1:
                ds_filtered = ds[ds > 0]
                if ds_filtered.size == 0:
                    div_scores[i] = 0.0
                else:
                    # take up to t nearest excluding self
                    div_scores[i] = np.mean(ds_filtered[:t])
            else:
                # fallback
                div_scores[i] = 0.0
    else:
        # fallback: per-row partial partition (avoid MxM)
        for i in range(M):
            dists = np.linalg.norm(nd_points - nd_points[i], axis=1)
            dists[i] = np.inf
            if M - 1 <= t:
                valid = dists != np.inf
                div_scores[i] = np.mean(dists[valid]) if np.any(valid) else 0.0
            else:
                ksmall = np.partition(dists, t)[:t]
                div_scores[i] = np.mean(ksmall)

    div_n = _norm(div_scores)

    # change weighting: favor diversity a bit more than original
    alpha = 0.4  # less weight on HV proxy, more on diversity
    surrogate = alpha * log_n + (1.0 - alpha) * div_n

    # Shortlist deterministically by surrogate (more aggressive, small adaptive)
    shortlist_size = min(M, max(int(3 * k + 5 * D), 20))
    shortlist_local_idx = np.argsort(-surrogate)[:shortlist_size]
    shortlist_set_local = set(int(i) for i in shortlist_local_idx)

    # Ensure at least k in shortlist
    if len(shortlist_local_idx) < k:
        need = k - len(shortlist_local_idx)
        remaining = [int(i) for i in range(M) if int(i) not in shortlist_set_local]
        add = remaining[:need]
        if add:
            shortlist_local_idx = np.concatenate([shortlist_local_idx, np.array(add, dtype=int)])
            shortlist_set_local.update(add)

    # HV cache keyed by frozenset of local indices
    hv_cache = {}

    def hv_of_local_indices(local_idxs):
        key = frozenset(int(i) for i in local_idxs)
        if key in hv_cache:
            return hv_cache[key]
        if len(key) == 0:
            hv_cache[key] = 0.0
            return 0.0
        arr = nd_points[sorted(key)]
        try:
            val = float(pg.hypervolume(arr).compute(reference_point.tolist()))
        except Exception:
            try:
                val = float(pg.hypervolume(arr).compute(reference_point))
            except Exception:
                val = 0.0
        hv_cache[key] = val
        return val

    # Precompute singleton HVs for shortlist locals (and maybe a few top others)
    singletons = {}
    for li in shortlist_local_idx:
        singletons[int(li)] = hv_of_local_indices([int(li)])

    # CELF lazy greedy on shortlist
    marginal_cache = {}  # li -> (marg, last_updated_selected_size)
    heap = []
    counter = 0
    for li in shortlist_local_idx:
        marg = float(singletons[int(li)])
        marginal_cache[int(li)] = (marg, 0)
        # deterministic tie-break: use surrogate and index
        tie = surrogate[int(li)]
        heapq.heappush(heap, (-marg, 0, tie, counter, int(li)))
        counter += 1

    selected_locals = []
    selected_set_local = set()
    hv_selected = 0.0
    selected_size = 0

    # Greedy selection with CELF and early stopping when top marginal <= 0
    while selected_size < k and heap:
        neg_marg, last_upd, tie, _cnt, li = heapq.heappop(heap)
        cached = marginal_cache.get(int(li), (None, -1))
        cached_marg, cached_iter = cached
        if cached_iter == selected_size:
            if cached_marg <= tol:
                break
            selected_locals.append(int(li))
            selected_set_local.add(int(li))
            selected_size += 1
            hv_selected = hv_of_local_indices(selected_locals)
            continue
        else:
            # recompute true marginal
            if selected_size == 0:
                new_marg = float(singletons[int(li)])
            else:
                hv_with = hv_of_local_indices(selected_locals + [int(li)])
                new_marg = hv_with - hv_selected
            marginal_cache[int(li)] = (new_marg, selected_size)
            tie2 = surrogate[int(li)]
            heapq.heappush(heap, (-new_marg, selected_size, tie2, counter, int(li)))
            counter += 1
            continue

    # Fill remaining slots deterministically by surrogate from shortlist first, then from all nd_points
    if selected_size < k:
        remaining_short = [i for i in shortlist_local_idx if i not in selected_set_local]
        rem_order = sorted(remaining_short, key=lambda x: -surrogate[int(x)])
        for li in rem_order:
            if len(selected_locals) >= k:
                break
            selected_locals.append(int(li))
            selected_set_local.add(int(li))
            hv_selected = hv_of_local_indices(selected_locals)
        if len(selected_locals) < k:
            remaining_all = [i for i in range(M) if i not in selected_set_local]
            rem_all_sorted = sorted(remaining_all, key=lambda x: -surrogate[int(x)])
            for li in rem_all_sorted:
                if len(selected_locals) >= k:
                    break
                selected_locals.append(int(li))
                selected_set_local.add(int(li))
                hv_selected = hv_of_local_indices(selected_locals)

    # Ensure exactly k elements (pad deterministically if necessary)
    if len(selected_locals) < k:
        last_choice = int(shortlist_local_idx[0]) if len(shortlist_local_idx) > 0 else 0
        while len(selected_locals) < k:
            if last_choice not in selected_set_local:
                selected_locals.append(last_choice)
                selected_set_local.add(last_choice)
            else:
                for i in range(M):
                    if i not in selected_set_local:
                        selected_locals.append(i)
                        selected_set_local.add(i)
                        break
                else:
                    break
        hv_selected = hv_of_local_indices(selected_locals)

    # Swap refinement: bounded first-improvement over a modest pool
    max_swap_iters = min(100, 20 * k)
    swap_iter = 0
    improved = True
    extras = [i for i in range(M) if i not in shortlist_set_local][:min(30, M)]
    swap_pool = sorted(set(list(shortlist_set_local) + extras))
    current_hv = hv_of_local_indices(selected_locals)
    while improved and swap_iter < max_swap_iters:
        improved = False
        swap_iter += 1
        for si_idx, a in enumerate(list(selected_locals)):
            for b in swap_pool:
                if b in selected_set_local:
                    continue
                swap_iter += 1
                trial = selected_locals.copy()
                trial[si_idx] = int(b)
                hv_trial = hv_of_local_indices(trial)
                if hv_trial > current_hv + tol:
                    selected_locals = trial
                    selected_set_local = set(selected_locals)
                    current_hv = hv_trial
                    improved = True
                    break
            if improved:
                break

    # Finalize selection to exactly k (preserve order)
    final_locals = selected_locals[:k]
    if len(final_locals) < k:
        rem = [i for i in range(M) if i not in final_locals]
        rem_sorted = sorted(rem, key=lambda x: -surrogate[x])
        for r in rem_sorted:
            if len(final_locals) >= k:
                break
            final_locals.append(r)
    final_locals = final_locals[:k]

    subset = nd_points[np.array(final_locals, dtype=int)]
    return subset.copy()

