            KDTree = None

    if KDTree is None:
        # compute per-point k-nearest mean distances without building full MxM when possible
        if M <= 2000:
            diff_mat = nd_points[:, None, :] - nd_points[None, :, :]
            dmat = np.linalg.norm(diff_mat, axis=2)
            for i in range(M):
                row = dmat[i].copy()
                row[i] = np.inf
                k_act = min(k_neigh, M - 1)
                if k_act > 0:
